PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?performerLabel ?title WHERE {
  wd:Q696096 wdt:P3311 ?recording .
  ?recording wdt:P175 ?performer ;
             wdt:P1476 ?title .
  ?performer rdfs:label ?performerLabel .
  FILTER(CONTAINS(LCASE(?title), "love me tender"))
  FILTER(LANG(?performerLabel) = "en")
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?track ?trackLabel ?performerLabel WHERE {
  wd:Q696096 wdt:P3255|wdt:P86|wdt:P1586 ?soundtrack .
  ?track wdt:P361 ?soundtrack ;
         wdt:P1476 ?trackLabel ;
         wdt:P175 ?performer .
  ?performer rdfs:label ?performerLabel .
  FILTER(LANG(?trackLabel) = "en" && LANG(?performerLabel) = "en")
  FILTER(CONTAINS(LCASE(?trackLabel), "love me tender"))
}
